function toggleSettingsMenu(){var e=document.getElementById("settingsMenu");e&&e.classList.toggle("hidden")}function toggleExcelSheetTabs(e){Excel.run(function(t){return t.workbook.getActiveWindow().showWorkbookTabs=e,t.sync()}).catch(function(e){console.log("Error toggling sheet tabs: "+e)})}Office.onReady(function(e){if(e.host===Office.HostType.Excel){var t=document.getElementById("settingsBtn");t&&(t.onclick=toggleSettingsMenu);var n=document.getElementById("toggle-sheet-tabs");n&&(n.onchange=function(){toggleExcelSheetTabs(n.checked)})}});